// Return current timestamp for queries
const now = new Date();
return [{ json: { now: now.toISOString(), today: now.toISOString().slice(0,10) } }];

const leadsRes = $('HTTP — Leads para follow-up').first().json;
const partnersRes = $('HTTP — Parceiros para follow-up').first().json;

const today = new Date();
const todayStr = today.toISOString().slice(0, 10);

// Leads due today or overdue
const dueleads = (leadsRes.data || []).filter(l => {
  if (!l.next_followup_at) return false;
  return l.next_followup_at.slice(0, 10) <= todayStr;
});

// Partners due today or overdue
const duePartners = (partnersRes.data || []).filter(p => {
  if (!p.next_followup_at) return false;
  return p.next_followup_at.slice(0, 10) <= todayStr;
});

const all = [
  ...dueleads.map(l => ({ ...l, _type: 'lead' })),
  ...duePartners.map(p => ({ ...p, _type: 'partner' })),
];

if (all.length === 0) return [];

return all.map(item => ({ json: item }));

